{"command": "cd $WORKSPACE_DIR && python3 -c "
from docx import Document
doc = Document('output/governance-diligence-memo.docx')
paras = [p.text for p in doc.paragraphs]
cells = []
for t in doc.tables:
    for row in t.rows:
        for c in row.cells:
            cells.append(c.text)
alltext = '\n'.join(paras+cells)
checks = {
 'No charter-control clause in SHA': 'no charter-control clause',
 'Voting Agreement 8.3 Charter controls': 'terms of the Restated Certificate shall control',
 'Committee must include Investor designee': 'each committee of the Board must include at least one Investor',
 'SHA 7.4 drag-along amendment consent': 'consent of each Investor Stockholder that would be adversely affected',
 'Matrix row 15 notice': 'Liquidation Event 20-day notice',
 'Matrix row 16 charter amendment': 'Charter amendment protective provisions',
 'Voting Agreement 8.4 amendment': 'adversely and disproportionately affect the rights of any Party',
}
for label,needle in checks.items():
    print(('OK  ' if needle in alltext else 'MISS')+' | '+label)
""}

